    # --- Portfolio (12 pairs) ---
    {"id": "port_001", "question": "What is portfolio diversification?", "expected_answer": "Diversification is spreading investments across different assets, sectors, and geographies to reduce unsystematic risk without necessarily sacrificing returns.", "category": "portfolio", "difficulty": "easy", "language": "en", "expected_intent": "factual"},
    {"id": "port_002", "question": "What is the efficient frontier?", "expected_answer": "The efficient frontier is the set of portfolios offering the highest expected return for a given level of risk, representing optimal risk-return combinations.", "category": "portfolio", "difficulty": "medium", "language": "en", "expected_intent": "factual"},
    {"id": "port_003", "question": "What is Modern Portfolio Theory?", "expected_answer": "MPT, developed by Markowitz, argues that assets should be evaluated by their contribution to overall portfolio risk and return, not in isolation.", "category": "portfolio", "difficulty": "medium", "language": "en", "expected_intent": "factual"},
    {"id": "port_004", "question": "Compare strategic vs tactical asset allocation.", "expected_answer": "Strategic allocation is a long-term target mix; tactical allocation makes short-term deviations to exploit market opportunities.", "category": "portfolio", "difficulty": "medium", "language": "en", "expected_intent": "analytical"},
