    {"id": "port_007", "question": "What are factor investing strategies?", "expected_answer": "Factor investing targets drivers of return like value, size, momentum, profitability and investment, popularised by the Fama-French models.", "category": "portfolio", "difficulty": "hard", "language": "en", "expected_intent": "factual"},
