    # --- Risk (12 pairs) ---
    {"id": "risk_001", "question": "What is sequence-of-returns risk?", "expected_answer": "Sequence-of-returns risk is the danger that poor returns early in retirement, combined with withdrawals, permanently impair the portfolio even if average returns are acceptable.", "category": "risk", "difficulty": "medium", "language": "en", "expected_intent": "factual"},
    {"id": "risk_002", "question": "How can I protect against inflation risk?", "expected_answer": "Protect against inflation using TIPS, real assets like real estate and commodities, and equities which can raise prices over time.", "category": "risk", "difficulty": "easy", "language": "en", "expected_intent": "planning"},
    {"id": "risk_003", "question": "What is longevity risk and how do I manage it?", "expected_answer": "Longevity risk is outliving assets. Manage it with annuities, delaying Social Security, and maintaining equity exposure for long-term growth.", "category": "risk", "difficulty": "medium", "language": "en", "expected_intent": "planning"},
    {"id": "risk_004", "question": "What is concentration risk?", "expected_answer": "Concentration risk is excessive exposure to a single stock, sector, or asset; common in employees holding large amounts of company stock.", "category": "risk", "difficulty": "easy", "language": "en", "expected_intent": "factual"},
    {"id": "risk_005", "question": "How does dollar-cost averaging reduce risk?", "expected_answer": "DCA reduces timing risk by investing fixed amounts regularly, buying more shares when prices are low and fewer when high.", "category": "risk", "difficulty": "easy", "language": "en", "expected_intent": "factual"},
    {"id": "risk_006", "question": "What is liquidity risk for investors?", "expected_answer": "Liquidity risk is the inability to sell assets quickly without significant loss; private equity and real estate carry high liquidity risk.", "category": "risk", "difficulty": "easy", "language": "en", "expected_intent": "factual"},
    {"id": "risk_007", "question": "Compare systematic and unsystematic risk.", "expected_answer": "Systematic (market) risk affects all assets and cannot be diversified away; unsystematic (idiosyncratic) risk is company-specific and reducible through diversification.", "category": "risk", "difficulty": "medium", "language": "en", "expected_intent": "analytical"},
    {"id": "risk_008", "question": "What is the bucket strategy for retirement?", "expected_answer": "The bucket strategy keeps 1-2 years of expenses in cash, 2-7 years in bonds, and long-term assets in equities to mitigate sequence-of-returns risk.", "category": "risk", "difficulty": "medium", "language": "en", "expected_intent": "factual"},
    {"id": "risk_009", "question": "How should I stress test my portfolio?", "expected_answer": "Stress test by simulating historical scenarios like 2008 or 2020, and hypothetical scenarios like stagflation, to assess portfolio resilience.", "category": "risk", "difficulty": "hard", "language": "en", "expected_intent": "planning"},
    {"id": "risk_010", "question": "What is behavioral risk in investing?", "expected_answer": "Behavioral risk is the danger of making poor decisions due to cognitive biases like loss aversion, recency bias, and overconfidence.", "category": "risk", "difficulty": "medium", "language": "en", "expected_intent": "factual"},
    {"id": "risk_011", "question": "What insurance products are part of risk management?", "expected_answer": "Key insurance products include term life, disability insurance, long-term care insurance, and umbrella liability to protect against various financial risks.", "category": "risk", "difficulty": "medium", "language": "en", "expected_intent": "factual"},
    {"id": "risk_012", "question": "What is an Investment Policy Statement?", "expected_answer": "An IPS documents an investor's goals, risk tolerance, and investment strategy, serving as a behavioral anchor during market volatility.", "category": "risk", "difficulty": "easy", "language": "en", "expected_intent": "factual"},

    # --- Retirement (11 pairs) ---
    {"id": "ret_001", "question": "What is the 4% withdrawal rule?", "expected_answer": "The 4% rule suggests retirees can withdraw 4% of initial portfolio value annually, adjusted for inflation, with high probability of the portfolio lasting 30 years.", "category": "retirement", "difficulty": "easy", "language": "en", "expected_intent": "factual"},
    {"id": "ret_002", "question": "What is the difference between Traditional and Roth IRA?", "expected_answer": "Traditional IRA uses pre-tax contributions with taxable withdrawals; Roth IRA uses after-tax contributions with tax-free growth and withdrawals.", "category": "retirement", "difficulty": "easy", "language": "en", "expected_intent": "analytical"},
    {"id": "ret_003", "question": "When should I start claiming Social Security?", "expected_answer": "Delaying to age 70 increases benefits by 8% per year past full retirement age; claim early only if health or immediate income needs require it.", "category": "retirement", "difficulty": "medium", "language": "en", "expected_intent": "planning"},
    {"id": "ret_004", "question": "What are Required Minimum Distributions?", "expected_answer": "RMDs are mandatory annual withdrawals from traditional IRAs and 401(k)s beginning at age 73; failure to take them incurs a 25% penalty.", "category": "retirement", "difficulty": "medium", "language": "en", "expected_intent": "factual"},
    {"id": "ret_005", "question": "How does compound interest affect retirement savings?", "expected_answer": "Compound interest grows savings exponentially over time; starting at 25 vs 35 can more than double final savings due to the extra decade of compounding.", "category": "retirement", "difficulty": "easy", "language": "en", "expected_intent": "factual"},
