    {"id": "ret_007", "question": "How do I plan for healthcare costs in retirement?", "expected_answer": "Budget for Medicare premiums, Medigap supplements, and long-term care costs; consider long-term care insurance or dedicated self-insurance savings.", "category": "retirement", "difficulty": "medium", "language": "en", "expected_intent": "planning"},
    {"id": "ret_008", "question": "What is a Qualified Charitable Distribution?", "expected_answer": "A QCD allows those over 70½ to donate up to $100,000 directly from an IRA to charity, satisfying RMD requirements while excluding the amount from taxable income.", "category": "retirement", "difficulty": "hard", "language": "en", "expected_intent": "factual"},
    {"id": "ret_009", "question": "Should I choose a 401k or IRA?", "expected_answer": "Maximise the 401(k) up to the employer match first, then fund a Roth IRA, then return to the 401(k) for additional pre-tax savings.", "category": "retirement", "difficulty": "medium", "language": "en", "expected_intent": "planning"},
    {"id": "ret_010", "question": "What is the U-shaped retirement spending pattern?", "expected_answer": "Spending is higher in early retirement for travel and activities, declines in middle retirement, and rises again in late retirement due to healthcare costs.", "category": "retirement", "difficulty": "medium", "language": "en", "expected_intent": "factual"},
    {"id": "ret_011", "question": "I want to retire at 55. Is the 4% rule safe for me?", "expected_answer": "The 4% rule assumes a 30-year horizon; retiring at 55 may require a 40+ year horizon, so a more conservative 3-3.5% withdrawal rate is advisable.", "category": "retirement", "difficulty": "hard", "language": "en", "expected_intent": "planning"},

    # --- Tax (10 pairs) ---
    {"id": "tax_001", "question": "What is tax-loss harvesting?", "expected_answer": "Tax-loss harvesting sells investments at a loss to offset capital gains, reducing current tax liability while maintaining market exposure via a similar replacement security.", "category": "tax", "difficulty": "medium", "language": "en", "expected_intent": "factual"},
    {"id": "tax_002", "question": "What is the wash-sale rule?", "expected_answer": "The wash-sale rule disallows a loss deduction if a substantially identical security is purchased within 30 days before or after the sale.", "category": "tax", "difficulty": "medium", "language": "en", "expected_intent": "factual"},
    {"id": "tax_003", "question": "What is asset location in tax planning?", "expected_answer": "Asset location places tax-inefficient assets like bonds in tax-deferred accounts and tax-efficient assets like equities in taxable accounts to maximise after-tax returns.", "category": "tax", "difficulty": "medium", "language": "en", "expected_intent": "factual"},
    {"id": "tax_004", "question": "What are long-term capital gains rates?", "expected_answer": "Long-term capital gains on assets held over one year are taxed at 0%, 15%, or 20% depending on taxable income, lower than ordinary income rates.", "category": "tax", "difficulty": "easy", "language": "en", "expected_intent": "factual"},
    {"id": "tax_005", "question": "What is a Donor Advised Fund?", "expected_answer": "A DAF allows an irrevocable charitable contribution in a high-income year for an immediate deduction, with grants to charities distributed over time.", "category": "tax", "difficulty": "medium", "language": "en", "expected_intent": "factual"},
    {"id": "tax_006", "question": "How do I donate appreciated stock to charity?", "expected_answer": "Donating appreciated stock directly to charity avoids capital gains tax while generating a deduction for the full fair market value.", "category": "tax", "difficulty": "medium", "language": "en", "expected_intent": "planning"},
    {"id": "tax_007", "question": "What is a 1031 exchange?", "expected_answer": "A 1031 exchange defers capital gains tax when selling investment property by reinvesting proceeds into a like-kind replacement property within prescribed timelines.", "category": "tax", "difficulty": "hard", "language": "en", "expected_intent": "factual"},
    {"id": "tax_008", "question": "Compare Roth and traditional 401k contributions.", "expected_answer": "Traditional 401(k) reduces current taxable income; Roth 401(k) uses after-tax dollars but provides tax-free growth. Choose based on current vs expected future tax rates.", "category": "tax", "difficulty": "medium", "language": "en", "expected_intent": "analytical"},
    {"id": "tax_009", "question": "What is the step-up in basis at death?", "expected_answer": "At death, inherited assets receive a stepped-up cost basis equal to fair market value, eliminating embedded capital gains for the heir.", "category": "tax", "difficulty": "hard", "language": "en", "expected_intent": "factual"},
    {"id": "tax_010", "question": "What is the Qualified Business Income deduction?", "expected_answer": "The QBI deduction allows eligible pass-through business owners to deduct up to 20% of qualified business income from taxable income.", "category": "tax", "difficulty": "hard", "language": "en", "expected_intent": "factual"},

    # --- Fixed Income (8 pairs) ---
    {"id": "fi_001", "question": "Why do bond prices fall when interest rates rise?", "expected_answer": "When rates rise, newly issued bonds offer higher yields, making existing lower-yielding bonds less attractive, so their prices fall to offer competitive yields.", "category": "fixed_income", "difficulty": "easy", "language": "en", "expected_intent": "factual"},
    {"id": "fi_002", "question": "What is bond duration?", "expected_answer": "Duration measures a bond's price sensitivity to interest rate changes; a 5-year duration bond falls ~5% in price for each 1% rise in rates.", "category": "fixed_income", "difficulty": "medium", "language": "en", "expected_intent": "factual"},
