    # --- Behavioral Finance (7 pairs) ---
    {"id": "beh_001", "question": "What is loss aversion?", "expected_answer": "Loss aversion is the tendency to feel losses approximately twice as intensely as equivalent gains, leading to holding losers too long and selling winners too early.", "category": "behavioral", "difficulty": "easy", "language": "en", "expected_intent": "factual"},
    {"id": "beh_002", "question": "What is recency bias in investing?", "expected_answer": "Recency bias leads investors to extrapolate recent market trends into the future, causing pro-cyclical buy-high, sell-low behaviour.", "category": "behavioral", "difficulty": "easy", "language": "en", "expected_intent": "factual"},
    {"id": "beh_003", "question": "What is overconfidence bias?", "expected_answer": "Overconfidence causes investors to overestimate their knowledge and predictive ability, leading to excessive trading and under-diversification.", "category": "behavioral", "difficulty": "easy", "language": "en", "expected_intent": "factual"},
    {"id": "beh_004", "question": "What is the disposition effect?", "expected_answer": "The disposition effect is the tendency to sell winning investments too early and hold losing ones too long, driven by loss aversion.", "category": "behavioral", "difficulty": "medium", "language": "en", "expected_intent": "factual"},
    {"id": "beh_005", "question": "How does herding affect markets?", "expected_answer": "Herding drives investors toward popular investments, amplifying trends and contributing to bubble formation and subsequent crashes.", "category": "behavioral", "difficulty": "medium", "language": "en", "expected_intent": "analytical"},
    {"id": "beh_006", "question": "What is mental accounting?", "expected_answer": "Mental accounting separates money into psychological buckets with different rules, leading to suboptimal decisions like holding cash while carrying high-interest debt.", "category": "behavioral", "difficulty": "medium", "language": "en", "expected_intent": "factual"},
    {"id": "beh_007", "question": "How can I overcome my investing biases?", "expected_answer": "Use pre-commitment devices like automatic investing, maintain an IPS, keep a decision journal, and work with an advisor for behavioural coaching.", "category": "behavioral", "difficulty": "medium", "language": "en", "expected_intent": "planning"},

