    # --- Real Estate (5 pairs) ---
    {"id": "re_001", "question": "What is a cap rate in real estate?", "expected_answer": "Cap rate is net operating income divided by purchase price; it measures the unlevered yield and is used to compare property values.", "category": "real_estate", "difficulty": "medium", "language": "en", "expected_intent": "factual"},
